  1338→const strSimilarity = (a, b) => {
  1339→    if (!a || !b) return 0;
  1340→    const la = a.toLowerCase().trim(), lb = b.toLowerCase().trim();
  1341→    if (la === lb) return 1;
  1342→    const longer = la.length > lb.length ? la : lb;
  1343→    const shorter = la.length > lb.length ? lb : la;
  1344→    if (!longer.length) return 1;
  1345→    const dp = Array.from({ length: shorter.length + 1 }, (_, i) => i);
  1346→    for (let i = 1; i <= longer.length; i++) {
  1347→        let prev = i;
  1348→        for (let j = 1; j <= shorter.length; j++) {
  1349→            const tmp = dp[j];
  1350→            dp[j] = longer[i-1] === shorter[j-1] ? dp[j-1] : 1 + Math.min(dp[j], prev, dp[j-1]);
  1351→            prev = tmp;
  1352→        }
  1353→    }
  1354→    return (longer.length - dp[shorter.length]) / longer.length;
  1355→};
