  1431→
  1432→    const variants = buildVariants(text);
  1433→
  1434→    // 1. Regex patterns — fast, high confidence
  1435→    const patternHit = checkPatterns(text, variants.norm);
  1436→    if (patternHit) return { detected: true, ...patternHit, signalScore: SIGNAL_WEIGHTS.pattern };
  1437→
  1438→    // 2. Personal info detection
  1439→    const infoHit = checkPersonalInfo(text);
  1440→    if (infoHit) return { detected: true, ...infoHit, signalScore: SIGNAL_WEIGHTS.personalInfo };
  1441→
  1442→    // 3. Word list match
  1443→    const rawWordHit = checkWordLists(variants);
  1444→    const wordHit = rawWordHit ? applyGlobalContextTolerance(text, rawWordHit) : null;
  1445→    if (wordHit) {
  1446→        const label =
  1447→            wordHit.type === 'abuse'    ? 'Abusive language' :
  1448→            wordHit.type === 'explicit' ? 'Explicit content' :
  1449→            wordHit.type === 'hate'     ? 'Hate speech' :
  1450→            wordHit.type === 'threat'   ? 'Threatening content' : 'Rule violation';
  1451→        return { detected: true, ...wordHit, label, signalScore: SIGNAL_WEIGHTS.wordlist };
  1452→    }
  1453→
  1454→    // 4. Fuzzy match — misspelling evasion
  1455→    const rawFuzzyHit = checkFuzzy(variants);
  1456→    const fuzzyHit = rawFuzzyHit ? applyGlobalContextTolerance(text, rawFuzzyHit) : null;
  1457→    if (fuzzyHit) {
  1458→        const label =
  1459→            fuzzyHit.type === 'abuse'    ? 'Abusive language (variant)' :
  1460→            fuzzyHit.type === 'explicit' ? 'Explicit content (variant)' :
  1461→            fuzzyHit.type === 'hate'     ? 'Hate speech (variant)' : 'Rule violation';
  1462→        const sev = ['low','medium','high','severe'];
  1463→        const idx = Math.max(0, sev.indexOf(fuzzyHit.severity) - 1);
  1464→        return { detected: true, ...fuzzyHit, severity: sev[idx], label, signalScore: SIGNAL_WEIGHTS.fuzzy };
  1465→    }
  1466→
  1467→    // 5. Multi-signal aggregation
  1468→    let totalScore = 0;
  1469→    let dominantHit = null;
  1470→
  1471→    const emojiHit = checkEmojiAbuse(text);
  1472→    if (emojiHit) {
  1473→        totalScore += emojiHit.score || SIGNAL_WEIGHTS.emoji;
  1474→        dominantHit = emojiHit;
  1475→    }
  1476→
  1477→    const capsHit = checkCapsAbuse(text);
  1478→    if (capsHit) {
  1479→        totalScore += SIGNAL_WEIGHTS.caps;
  1480→        if (!dominantHit) dominantHit = capsHit;
  1481→    }
  1482→
  1483→    // Check context abbreviations: fire only if another signal is present
  1484→    const lower = text.toLowerCase();
  1485→    for (const abbrev of CONTEXT_ABBREVS) {
  1486→        if (lower.split(/\s+/).includes(abbrev) && totalScore > 0) {
  1487→            totalScore += SIGNAL_WEIGHTS.abbrev;
  1488→            if (!dominantHit) dominantHit = { type:'abuse', severity:'medium', label:'Abusive language' };
  1489→            break;
  1490→        }
  1491→    }
