  1715→    if (!hit) return;
  1716→
  1717→    // ── Adult Room exemption ──────────────────────────────────────────────────
  1718→    // The Adult Room allows consensual adult conversations. However it remains
  1719→    // strictly enforced for: family abuse, incest, minors, non-consensual content,
  1720→    // religious abuse, hate speech, threats, scams, doxxing, and spam.
