  1747→    // Non-staff: detection only — no Firestore writes
  1748→    if (!isStaff) return;
  1749→
  1750→    // Per-user action cooldown — prevents hammering same user with rapid actions
  1751→    if (!canTakeAction(uid)) return;
  1752→
  1753→    // Determine escalation action
  1754→    let action = 'warn', shouldDelete = false, muteDuration = 0, shouldKick = false;
  1755→
  1756→    if      (priorTotal >= CFG.KICK_AT)    { action='kick';     shouldDelete=true; shouldKick=true; }
  1757→    else if (priorTotal >= CFG.MUTE_24H_AT){ action='mute_24h'; shouldDelete=true; muteDuration=24*60*60*1000; }
  1758→    else if (priorTotal >= CFG.MUTE_3H_AT) { action='mute_3h';  shouldDelete=true; muteDuration=3*60*60*1000; }
  1759→    else if (priorTotal >= CFG.MUTE_30_AT) { action='mute_30';  shouldDelete=true; muteDuration=30*60*1000; }
  1760→    else if (priorTotal >= CFG.MUTE_5_AT)  { action='mute_5';   shouldDelete=true; muteDuration=5*60*1000; }
