  1764→    // Severity overrides
  1765→    if ((hit.severity==='high'||hit.severity==='severe') && !shouldDelete) {
  1766→        shouldDelete=true; action='delete_warn';
  1767→    }
  1768→    if (hit.severity==='severe' && muteDuration===0 && !shouldKick) {
  1769→        muteDuration=5*60*1000; action='mute_5';
  1770→    }
