  1782→    // Execute enforcement
  1783→    if (shouldDelete) await removeMessage(roomId, msg.id);
  1784→    if (muteDuration > 0) await muteUser(uid, muteDuration, `TingleBot: ${hit.label} (violation #${priorTotal+1})`);
