  1791→    }
  1792→
  1793→    // Build and post notice (with per-type cooldown)
  1794→    const noticeCooldownType = shouldKick ? 'kick' : muteDuration > 0 ? 'mute' : 'warn';
  1795→    if (!canPostNotice(uid, noticeCooldownType)) return;
  1796→
  1797→    let noticeText, tinglebotType;
  1798→    if (shouldKick) {
  1799→        noticeText = getRandom(NOTICE_VARIANTS.kicked(displayName));
  1800→        tinglebotType = 'kicked';
  1801→    } else if (muteDuration > 0) {
  1802→        noticeText = getRandom(NOTICE_VARIANTS.muted(displayName, fmtDuration(muteDuration), hit.label));
  1803→        tinglebotType = 'muted';
  1804→    } else if (shouldDelete) {
  1805→        noticeText = getRandom(NOTICE_VARIANTS.delete_warn.map(fn => fn(displayName, hit.label)));
  1806→        tinglebotType = 'automod';
  1807→    } else {
  1808→        noticeText = getRandom(NOTICE_VARIANTS.warn.map(fn => fn(displayName, hit.label)));
  1809→        tinglebotType = 'automod';
  1810→    }
  1811→
  1812→    await postNotice(roomId, noticeText, tinglebotType);
  1813→};
